// pages/employer/EmployerAnalytics.jsx
import React, { useState } from 'react';
import { ANALYTICS, POSTED_INTERNSHIPS } from '../../data/mockEmployerData';
import './EmployerAnalytics.css';

/* ── Pure CSS bar chart helpers ── */
function BarChart({ data, valueKey, labelKey, color = 'lavender', max }) {
  const peak = max || Math.max(...data.map(d => d[valueKey]));
  return (
    <div className="ana-chart__bars">
      {data.map((d, i) => (
        <div key={i} className="ana-chart__bar-group">
          <div className="ana-chart__bar-track">
            <div
              className={`ana-chart__bar ana-chart__bar--${color}`}
              style={{ height: `${(d[valueKey] / peak) * 100}%`, animationDelay: `${i * 60}ms` }}
            />
          </div>
          <span className="ana-chart__bar-val">{d[valueKey]}</span>
          <span className="ana-chart__bar-label">{d[labelKey]}</span>
        </div>
      ))}
    </div>
  );
}

function HBarChart({ data, valueKey, labelKey, color = 'lavender' }) {
  const peak = Math.max(...data.map(d => d[valueKey]));
  return (
    <div className="ana-hbar__list">
      {data.map((d, i) => (
        <div key={i} className="ana-hbar__row">
          <span className="ana-hbar__label">{d[labelKey]}</span>
          <div className="ana-hbar__track">
            <div
              className={`ana-hbar__fill ana-hbar__fill--${color}`}
              style={{ width: `${(d[valueKey] / peak) * 100}%`, animationDelay: `${i * 80}ms` }}
            />
          </div>
          <span className="ana-hbar__val">{d[valueKey]}</span>
        </div>
      ))}
    </div>
  );
}

function FunnelChart({ data }) {
  const max = data[0].applied;
  const stages = [
    { label: 'Applied',     key: 'applied',     color: 'lavender' },
    { label: 'Shortlisted', key: 'shortlisted',  color: 'amber' },
    { label: 'Interview',   key: 'interview',    color: 'cyan' },
    { label: 'Hired',       key: 'hired',        color: 'mint' },
  ];
  // aggregate across all roles
  const totals = stages.map(s => ({
    ...s,
    count: data.reduce((sum, r) => sum + r[s.key], 0),
  }));
  const totalApplied = totals[0].count;

  return (
    <div className="ana-funnel">
      {totals.map((s, i) => {
        const pct = Math.round((s.count / totalApplied) * 100);
        const width = 100 - i * 14;
        return (
          <div key={s.key} className="ana-funnel__stage" style={{ animationDelay: `${i * 100}ms` }}>
            <div className="ana-funnel__bar-wrap" style={{ width: `${width}%` }}>
              <div className={`ana-funnel__bar ana-funnel__bar--${s.color}`} />
            </div>
            <div className="ana-funnel__info">
              <span className="ana-funnel__label">{s.label}</span>
              <span className="ana-funnel__count">{s.count}</span>
              <span className="ana-funnel__pct">{pct}%</span>
            </div>
          </div>
        );
      })}
    </div>
  );
}

export default function EmployerAnalytics() {
  const [roleFilter, setRoleFilter] = useState('all');

  const STAT_CARDS = [
    { icon: '👁️',  label: 'Total Listing Views',  value: ANALYTICS.totalViews,    color: 'lavender' },
    { icon: '📥',  label: 'Total Applicants',     value: POSTED_INTERNSHIPS.reduce((s,i) => s+i.applicants, 0), color: 'mint' },
    { icon: '⚡',  label: 'Avg. Time to Hire',    value: `${ANALYTICS.avgTimeToHire}d`, color: 'cyan' },
    { icon: '✅',  label: 'Conversion Rate',       value: `${ANALYTICS.conversionRate}%`, color: 'amber' },
  ];

  const filteredRoles = roleFilter === 'all'
    ? ANALYTICS.applicantsPerRole
    : ANALYTICS.applicantsPerRole.filter(r => r.role.toLowerCase().includes(roleFilter));

  return (
    <div className="emp-ana page-enter">
      <div className="emp-ana__header">
        <div>
          <div className="section-label">Employer</div>
          <h1 className="emp-ana__title">Analytics</h1>
          <p className="emp-ana__sub">Performance data across all your listings and trainings.</p>
        </div>
        <div className="emp-ana__date-badge">📅 Mar 2025</div>
      </div>

      {/* KPI CARDS */}
      <div className="emp-ana__kpis">
        {STAT_CARDS.map(s => (
          <div key={s.label} className={`emp-ana__kpi emp-ana__kpi--${s.color}`}>
            <span className="emp-ana__kpi-icon">{s.icon}</span>
            <span className="emp-ana__kpi-value">{s.value}</span>
            <span className="emp-ana__kpi-label">{s.label}</span>
          </div>
        ))}
      </div>

      <div className="emp-ana__grid">
        {/* WEEKLY APPLICANTS */}
        <div className="emp-ana__card emp-ana__card--wide">
          <div className="emp-ana__card-header">
            <h3 className="emp-ana__card-title">Weekly Applicants</h3>
            <span className="emp-ana__card-sub">Last 8 weeks</span>
          </div>
          <div className="ana-chart__wrap">
            <BarChart data={ANALYTICS.weeklyApplicants} valueKey="count" labelKey="week" color="lavender" />
          </div>
        </div>

        {/* PIPELINE FUNNEL */}
        <div className="emp-ana__card">
          <div className="emp-ana__card-header">
            <h3 className="emp-ana__card-title">Hiring Funnel</h3>
            <span className="emp-ana__card-sub">All roles combined</span>
          </div>
          <FunnelChart data={ANALYTICS.applicantsPerRole} />
        </div>

        {/* APPLICANTS PER ROLE */}
        <div className="emp-ana__card emp-ana__card--wide">
          <div className="emp-ana__card-header">
            <h3 className="emp-ana__card-title">Applicants by Role</h3>
            <div className="emp-ana__legend">
              <span className="emp-ana__legend-dot emp-ana__legend-dot--lavender"/>Applied
              <span className="emp-ana__legend-dot emp-ana__legend-dot--amber"/>Shortlisted
              <span className="emp-ana__legend-dot emp-ana__legend-dot--cyan"/>Interview
              <span className="emp-ana__legend-dot emp-ana__legend-dot--mint"/>Hired
            </div>
          </div>
          <div className="emp-ana__role-bars">
            {ANALYTICS.applicantsPerRole.map((r, i) => (
              <div key={i} className="emp-ana__role-row">
                <span className="emp-ana__role-name">{r.role}</span>
                <div className="emp-ana__role-track">
                  {[
                    { key:'applied',     color:'lavender', val: r.applied },
                    { key:'shortlisted', color:'amber',    val: r.shortlisted },
                    { key:'interview',   color:'cyan',     val: r.interview },
                    { key:'hired',       color:'mint',     val: r.hired },
                  ].map(s => (
                    <div key={s.key} className="emp-ana__role-segment-wrap" title={`${s.key}: ${s.val}`}>
                      <div
                        className={`emp-ana__role-segment emp-ana__role-segment--${s.color}`}
                        style={{ width: `${(s.val / r.applied) * 100}%` }}
                      />
                      <span className="emp-ana__role-segment-val">{s.val}</span>
                    </div>
                  ))}
                </div>
              </div>
            ))}
          </div>
        </div>

        {/* TOP SKILLS */}
        <div className="emp-ana__card">
          <div className="emp-ana__card-header">
            <h3 className="emp-ana__card-title">Top Skills in Applicant Pool</h3>
            <span className="emp-ana__card-sub">Most common across all applications</span>
          </div>
          <HBarChart data={ANALYTICS.topSkills} valueKey="count" labelKey="skill" color="cyan" />
        </div>

        {/* COLLEGE BREAKDOWN */}
        <div className="emp-ana__card">
          <div className="emp-ana__card-header">
            <h3 className="emp-ana__card-title">Applicants by College Tier</h3>
            <span className="emp-ana__card-sub">Distribution of applicant background</span>
          </div>
          <div className="emp-ana__donut-wrap">
            {ANALYTICS.collegeBreakdown.map((c, i) => {
              const colors = ['lavender','mint','cyan','amber','peach'];
              const total = ANALYTICS.collegeBreakdown.reduce((s,x) => s + x.count, 0);
              const pct = Math.round((c.count / total) * 100);
              return (
                <div key={i} className="emp-ana__college-row">
                  <div className={`emp-ana__college-bar-track`}>
                    <div
                      className={`emp-ana__college-bar emp-ana__college-bar--${colors[i]}`}
                      style={{ width: `${pct}%`, animationDelay: `${i * 80}ms` }}
                    />
                  </div>
                  <span className="emp-ana__college-label">{c.college}</span>
                  <span className="emp-ana__college-count">{c.count} <span className="emp-ana__college-pct">({pct}%)</span></span>
                </div>
              );
            })}
          </div>
        </div>

        {/* LISTING PERFORMANCE TABLE */}
        <div className="emp-ana__card emp-ana__card--full">
          <div className="emp-ana__card-header">
            <h3 className="emp-ana__card-title">Listing Performance</h3>
          </div>
          <div className="emp-ana__table-wrap">
            <table className="emp-ana__table">
              <thead>
                <tr>
                  <th>Role</th>
                  <th>Status</th>
                  <th>Views</th>
                  <th>Applied</th>
                  <th>Shortlisted</th>
                  <th>Hired</th>
                  <th>Conv. Rate</th>
                </tr>
              </thead>
              <tbody>
                {POSTED_INTERNSHIPS.map(i => {
                  const conv = i.applicants > 0 ? ((i.hired / i.applicants) * 100).toFixed(1) : '0.0';
                  return (
                    <tr key={i.id}>
                      <td className="emp-ana__table-role">{i.role}</td>
                      <td>
                        <span className={`emp-ana__table-status emp-ana__table-status--${i.status === 'active' ? 'mint' : i.status === 'paused' ? 'amber' : 'peach'}`}>
                          {i.status}
                        </span>
                      </td>
                      <td>{i.views || '—'}</td>
                      <td><strong>{i.applicants}</strong></td>
                      <td>{i.shortlisted}</td>
                      <td>{i.hired}</td>
                      <td>
                        <span className={`emp-ana__conv ${parseFloat(conv) > 3 ? 'emp-ana__conv--good' : ''}`}>
                          {conv}%
                        </span>
                      </td>
                    </tr>
                  );
                })}
              </tbody>
            </table>
          </div>
        </div>
      </div>
    </div>
  );
}
